export const 太上符三 = (bi) => {
    const u = bi.u, k = 2.35;
    const X = (c) => (c - 3.95) * k;
    const Z = (r) => (r - 2.0) * k + 1.0;
    const 線 = (書, 寬 = 0.55) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '回' }, 書);
    const 出 = (書, 寬 = 0.58) => bi.一筆({ 寬: 寬 * u, 起: '藏', 收: '出' }, 書);
    // 太上冠：頂小鉤・大橫・左右長弧腳・上字
    出(p => p.M(X(3.75), Z(2.2)).C(X(3.85), Z(2.6), X(3.95), Z(2.9), X(4.0), Z(3.1)), 0.5);
    線(p => p.M(X(0.55), Z(3.6)).L(X(7.25), Z(3.52)), 0.62);
    出(p => p.M(X(3.85), Z(3.65)).C(X(2.6), Z(4.8), X(1.3), Z(5.6), X(0.8), Z(6.6)).L(X(0.78), Z(10.6)), 0.6);
    出(p => p.M(X(4.05), Z(3.65)).C(X(5.3), Z(4.8), X(6.6), Z(5.6), X(7.1), Z(6.6)).L(X(7.08), Z(8.6)), 0.6);
    線(p => p.M(X(3.95), Z(4.1)).L(X(3.93), Z(6.0)), 0.55);
    // 冠腳彎合
    出(p => p.M(X(0.78), Z(10.6)).C(X(0.9), Z(11.1), X(1.7), Z(11.35), X(3.0), Z(11.3)), 0.58);
    出(p => p.M(X(7.08), Z(8.6)).C(X(7.0), Z(9.3), X(6.6), Z(9.7), X(6.1), Z(9.8)), 0.58);
    線(p => p.M(X(4.05), Z(4.9)).L(X(5.1), Z(4.86)), 0.5);
    線(p => p.M(X(2.5), Z(6.1)).L(X(5.6), Z(6.04)), 0.55);
    // 敕曲核心
    線(p => p.M(X(1.7), Z(8.5)).L(X(4.6), Z(8.44)), 0.55);
    線(p => p.M(X(2.95), Z(7.8)).L(X(2.93), Z(10.4)), 0.55);
    出(p => p.M(X(2.95), Z(9.7)).L(X(2.2), Z(10.5)), 0.45);
    出(p => p.M(X(3.0), Z(9.7)).L(X(3.7), Z(10.4)), 0.45);
    線(p => p.M(X(4.6), Z(8.0)).C(X(5.9), Z(7.9), X(6.3), Z(8.7), X(5.3), Z(9.0)).C(X(4.4), Z(9.3), X(4.5), Z(10.0), X(5.5), Z(10.1)).C(X(6.1), Z(10.16), X(6.3), Z(10.5), X(6.2), Z(10.8)), 0.55);
    // 大迴摺帶
    線(p => p.M(X(6.3), Z(11.6)).C(X(1.4), Z(11.7), X(1.0), Z(12.6), X(2.2), Z(12.75)).L(X(5.2), Z(12.65)).C(X(6.3), Z(12.7), X(6.3), Z(13.6), X(5.2), Z(13.7)).L(X(1.6), Z(13.8)).L(X(1.58), Z(16.6)), 0.6);
    // 川垂四縷（右三縷波・左心曲）
    出(p => p.M(X(4.3), Z(14.6)).C(X(4.1), Z(15.6), X(4.5), Z(16.6), X(4.3), Z(17.6)), 0.45);
    出(p => p.M(X(5.1), Z(14.55)).C(X(4.9), Z(15.55), X(5.3), Z(16.55), X(5.1), Z(17.5)), 0.45);
    出(p => p.M(X(5.9), Z(14.5)).C(X(5.7), Z(15.5), X(6.1), Z(16.5), X(5.9), Z(17.4)), 0.45);
    出(p => p.M(X(6.55), Z(14.5)).C(X(6.4), Z(15.3), X(6.7), Z(16.1), X(6.55), Z(16.9)), 0.45);
    // 人字蓋承与鉤長垂
    出(p => p.M(X(3.9), Z(18.2)).C(X(2.9), Z(18.9), X(1.9), Z(19.4), X(1.1), Z(19.7)), 0.55);
    出(p => p.M(X(4.0), Z(18.2)).C(X(5.0), Z(18.9), X(6.0), Z(19.4), X(6.8), Z(19.7)), 0.55);
    線(p => p.M(X(3.3), Z(20.2)).C(X(4.9), Z(20.1), X(5.3), Z(20.8), X(4.1), Z(21.0)).C(X(3.1), Z(21.2), X(3.1), Z(21.9), X(4.2), Z(22.0)), 0.55);
    出(p => p.M(X(4.2), Z(22.1)).C(X(4.4), Z(23.0), X(4.2), Z(24.0), X(4.0), Z(24.8)), 0.58);
};
